css:
* { margin: 0; padding: 0; box-sizing: border-box; font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif; }
body { background: #08070d; color: white; overflow-x: hidden; }
.navbar { display: flex; justify-content: space-between; align-items: center; padding: 24px 60px; position: relative; z-index: 2; }
.brand { font-size: 18px; font-weight: 800; letter-spacing: 0.08em; }
.nav-links { display: flex; gap: 28px; }
.nav-links a { color: rgba(255,255,255,0.5); text-decoration: none; font-size: 14px; font-weight: 600; }
.nav-links a.active { color: #818cf8; }
.hero { position: relative; padding: 70px 60px 100px; max-width: 700px; }
.hero-bg { position: absolute; inset: 0; background: radial-gradient(circle at 80% 20%, rgba(99,102,241,0.25), transparent 55%); z-index: -1; }
.badge { display: inline-block; color: #818cf8; font-size: 12px; font-weight: 800; letter-spacing: 0.18em; margin-bottom: 22px; }
.hero h1 { font-size: 52px; font-weight: 800; line-height: 1.25; margin-bottom: 18px; }
.hero h1 span { color: #818cf8; }
.hero p { color: rgba(255,255,255,0.5); font-size: 15px; line-height: 1.8; margin-bottom: 28px; }
.btn-primary { background: linear-gradient(135deg, #6366f1, #818cf8); border: none; color: white; padding: 15px 32px; border-radius: 999px; font-size: 14px; font-weight: 700; cursor: pointer; box-shadow: 0 12px 30px rgba(99,102,241,0.3); }
.discography { padding: 0 60px 50px; }
.discography h2 { font-size: 28px; font-weight: 800; margin-bottom: 24px; }
.album-grid { display: grid; grid-template-columns: repeat(auto-fit, minmax(180px, 1fr)); gap: 20px; }
.album-card { cursor: pointer; }
.album-art { aspect-ratio: 1; background: linear-gradient(150deg, #1e1b3a, #08070d); border-radius: 16px; display: flex; align-items: center; justify-content: center; font-size: 50px; margin-bottom: 12px; transition: 0.2s; }
.album-card:hover .album-art { transform: scale(1.03); }
.album-card h3 { font-size: 15px; font-weight: 700; margin-bottom: 4px; }
.album-card span { font-size: 12px; color: rgba(255,255,255,0.4); }
.player-section { padding: 0 60px 60px; }
.player { display: flex; align-items: center; gap: 16px; background: rgba(255,255,255,0.04); border: 1px solid rgba(255,255,255,0.08); border-radius: 18px; padding: 18px 22px; }
.player-art { width: 60px; height: 60px; background: linear-gradient(150deg, #1e1b3a, #08070d); border-radius: 12px; display: flex; align-items: center; justify-content: center; font-size: 28px; flex-shrink: 0; }
.player-info { flex: 1; }
.player-info h3 { font-size: 15px; font-weight: 700; margin-bottom: 2px; }
.player-info span { font-size: 12px; color: rgba(255,255,255,0.4); }
.track-bar { height: 5px; background: rgba(255,255,255,0.08); border-radius: 999px; overflow: hidden; margin-top: 10px; }
.track-fill { height: 100%; width: 0%; background: linear-gradient(90deg, #6366f1, #818cf8); border-radius: 999px; transition: 1s linear; }
.play-btn { width: 50px; height: 50px; border-radius: 50%; background: linear-gradient(135deg, #6366f1, #818cf8); border: none; color: white; font-size: 16px; cursor: pointer; flex-shrink: 0; }
.shows { padding: 0 60px 60px; }
.shows h2 { font-size: 28px; font-weight: 800; margin-bottom: 22px; }
.show-list { display: flex; flex-direction: column; gap: 12px; }
.show-item { display: flex; align-items: center; gap: 20px; background: rgba(255,255,255,0.03); border: 1px solid rgba(255,255,255,0.07); border-radius: 16px; padding: 16px 20px; }
.show-date { display: flex; flex-direction: column; align-items: center; background: rgba(99,102,241,0.12); border-radius: 12px; padding: 8px 14px; flex-shrink: 0; }
.show-date .day { font-size: 20px; font-weight: 800; color: #818cf8; }
.show-date .month { font-size: 11px; color: rgba(255,255,255,0.5); font-weight: 700; text-transform: uppercase; }
.show-info { flex: 1; }
.show-info h3 { font-size: 15px; font-weight: 700; }
.show-info span { font-size: 12px; color: rgba(255,255,255,0.4); }
.show-item button { background: rgba(255,255,255,0.06); border: none; color: white; padding: 10px 20px; border-radius: 999px; font-size: 12.5px; font-weight: 700; cursor: pointer; }
.contact { text-align: center; padding: 80px 60px; background: linear-gradient(135deg, rgba(99,102,241,0.08), transparent); }
.contact h2 { font-size: 28px; font-weight: 800; margin-bottom: 10px; }
.contact p { color: rgba(255,255,255,0.5); font-size: 14px; margin-bottom: 26px; }
.contact button { background: rgba(255,255,255,0.06); border: 1px solid rgba(255,255,255,0.15); color: white; padding: 15px 32px; border-radius: 999px; font-size: 14px; font-weight: 700; cursor: pointer; }
@media (max-width: 900px) { .navbar, .hero, .discography, .player-section, .shows, .contact { padding-left: 24px; padding-right: 24px; } .nav-links { display: none; } .hero h1 { font-size: 34px; } }

js:
const tracks = [
  { title: 'Kıyı - Açılış', album: 'Kıyı, 2026', art: '🌊' },
  { title: 'Gece Yarısı Düşünceleri', album: 'Gece Yarısı Düşünceleri, 2024', art: '🌙' },
  { title: 'Sonbahar Defteri - Tema', album: 'Sonbahar Defteri, 2022', art: '🍂' }
];

let currentTrack = 0;
let playing = false;
let progress = 0;
let timer = null;

function playTrack(index) {
  currentTrack = index;
  progress = 0;
  document.getElementById('progressFillDummy');
  render();
  if (!playing) togglePlay();
  else { clearInterval(timer); progress = 0; document.getElementById('trackFill').style.width = '0%'; startTimer(); }
}

function render() {
  const t = tracks[currentTrack];
  document.getElementById('playerTitle').textContent = t.title;
  document.getElementById('playerAlbum').textContent = t.album;
  document.getElementById('playerArt').textContent = t.art;
}

function togglePlay() {
  playing = !playing;
  document.getElementById('playBtn').textContent = playing ? '❚❚' : '▶';
  if (playing) startTimer();
  else clearInterval(timer);
}

function startTimer() {
  clearInterval(timer);
  timer = setInterval(() => {
    progress = Math.min(progress + 1, 100);
    document.getElementById('trackFill').style.width = progress + '%';
    if (progress >= 100) { clearInterval(timer); playing = false; document.getElementById('playBtn').textContent = '▶'; }
  }, 300);
}

